}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**锚定真实成交价**:用各地房管局网签备案的真实成交价(法律意义的成交)做价格锚,辅以贝壳「成交记录」和中国房价行情网小区历史曲线 —— 绝不用中介挂牌价当估值依据(下行期挂牌价系统性偏高 10-20%)。inputs: 网签数据 + 平台成交记录;outputs: 合理价格区间。"
  "**产权核查(不动产登记中心查档)**:查「他项权利」(有没有抵押、抵押给谁、金额)、「查封」(有没有被法院查封、有没有轮候查封)、「权利人」(卖方身份与产权证一致、共有产权人是否齐全)、「规划用途/性质」(住宅 vs 商办 40 年产权 vs 划拨地)、「面积与四至」。inputs: 不动产登记查档;outputs: 产权核查结论。"
  "**算完整持有账(自建 Excel)**:买入端(首付+契税+增值税+个税+中介费+贷款手续费)+ 持有端(月供利息+物业+维修+空置损失+资金占用机会成本+房产税试点城市加这项)+ 收益端(扣空置的真实租金,资本利得在 2024-2025 敢填 0 甚至负)+ 退出端(卖出税费+中介费+流动性折价)。inputs: LPR+税费政策+租金数据;outputs: 净租金回报率、盈亏平衡持有年限。"
  "**跑压力测试**:模型必须跑「房价跌 20% / 租金跌 30% / 利率升 1%」三个压力场景,看现金流会不会断。inputs: 持有账模型;outputs: 压力情景下的现金流结论。"
  "**出尽调结论**:价格在合理区间 + 产权干净 + 完整账划算 + 压力测试能扛 —— 四项全过才保留;产权有任何瑕疵(抵押未明、查封、性质不符)直接淘汰或要求卖方先解决。"
)
declare -a FAILURE_MODES=(
  "**信中介一句「房子很干净」就跳过查档**:触发原因 = 嫌查档麻烦 + 信任中介;怎么避免 = 每套房无论一手二手法拍都必须自己到不动产登记中心查档。Don't: 听中介说「产权没问题」就付定金,过户时才发现房子有抵押/被查封,定金和时间全打水漂,甚至卷入诉讼。"
  "**用挂牌价当成交价估值**:触发原因 = 平台上只看得到挂牌价;怎么避免 = 成交价锚定回房管局网签,挂牌价只看「卖家心理预期」。"
  "**只算月供当完整账**:触发原因 = 用市面房贷计算器;怎么避免 = 自建 Excel 算完整持有账并跑压力测试,月供能扛 ≠ 投资划算。Don't: 算完月供觉得「能负担」就买,忽略物业/空置/资金占用/退出税费/流动性折价,年年净流出。"
  "**估值不留政策余量**:触发原因 = 按「房产税永远不收」「政策永远松」算;怎么避免 = 持有成本测算为房产税扩围预留弹性,读政策、留余量。"
  "**Decay risk**: medium —— 产权核查方法稳定(法定登记制度,low),但税费税率/参考价政策/房产税进展/利率参数是 12 个月内会变的高频项,整体 medium。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
